import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is the greatest common factor?", a: "The greatest common factor is the largest positive integer that divides all numbers in a set with no remainder." },
  { q: "How do you find the GCF using prime factorization?", a: "Prime factor each number, then multiply only the prime factors shared by all numbers using the lowest power found in every factorization." },
  { q: "What is the Euclidean algorithm?", a: "The Euclidean algorithm finds the GCF by repeatedly replacing two numbers with the smaller number and the remainder until the remainder is zero." },
  { q: "What is the GCF used for?", a: "GCF is used to simplify fractions, factor expressions, divide groups evenly, and solve number theory problems." },
  { q: "What is the difference between GCF and LCM?", a: "GCF is the greatest shared factor, while LCM is the smallest shared multiple. GCF divides numbers, while LCM is divisible by them." },
];

const gcd = (a: number, b: number): number => b === 0 ? Math.abs(a) : gcd(b, a % b);
const factorMap = (n: number) => {
  const out: Record<number, number> = {};
  let x = Math.abs(n);
  for (let p = 2; p * p <= x; p++) while (x % p === 0) { out[p] = (out[p] || 0) + 1; x /= p; }
  if (x > 1) out[x] = (out[x] || 0) + 1;
  return out;
};
const text = (f: Record<number, number>) => Object.entries(f).map(([p, e]) => e === 1 ? p : `${p}^${e}`).join(" x ") || "1";

export default function GCFCalculator() {
  const [input, setInput] = useState("48, 72, 120");
  const result = useMemo(() => {
    const nums = input.split(/[\s,;]+/).map((n) => Math.abs(Math.trunc(Number(n)))).filter((n) => Number.isFinite(n) && n > 0).slice(0, 10);
    if (nums.length < 2) return null;
    const gcf = nums.reduce((acc, n) => gcd(acc, n));
    const maps = nums.map(factorMap);
    const common: Record<number, number> = {};
    Object.keys(maps[0]).forEach((prime) => {
      const powers = maps.map((m) => m[Number(prime)] || 0);
      const min = Math.min(...powers);
      if (min > 0) common[Number(prime)] = min;
    });
    const euclid = nums.slice(1).reduce((lines, n, i) => [...lines, `GCF(${i === 0 ? nums[0] : "previous"}, ${n}) = ${gcd(i === 0 ? nums[0] : nums.slice(0, i + 1).reduce((a, b) => gcd(a, b)), n)}`], [] as string[]);
    return { nums, gcf, maps, common, euclid };
  }, [input]);

  return (
    <>
      <SEOHead title="Free GCF Calculator Online - Find Greatest Common Factor of Any Numbers Instantly | CalcHive" description="Free online GCF calculator. Find the greatest common factor of two or more numbers instantly with step by step solution. 100% free for students and everyone, no signup required." canonical="/gcf-calculator" keywords="free GCF calculator, greatest common factor calculator free online, GCD calculator free, find GCF free, greatest common divisor calculator free online" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Greatest Common Factor Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free GCF calculator to find GCF free with prime factorization and Euclidean algorithm steps.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <label htmlFor="gcf-input" className="text-sm font-semibold text-foreground block mb-2">Numbers, up to 10</label>
          <input id="gcf-input" value={input} onChange={(event) => setInput(event.target.value)} className="w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
          {result ? <motion.div key={input} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }} className="mt-8">
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Greatest Common Factor</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-gcf">{result.gcf.toLocaleString()}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.nums.map((n, i) => `${n} = ${text(result.maps[i])}`).join("; ")}. Shared prime factors: {text(result.common)} = {result.gcf}. Euclidean check: {result.euclid.join("; ")}.</p></div>
          </motion.div> : <p className="text-center text-muted-foreground py-6">Enter at least two positive integers.</p>}
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Find the GCF of Any Numbers for Free</h2><p className="text-muted-foreground leading-relaxed">Enter two or more numbers and this greatest common divisor calculator free online tool finds the largest shared factor.</p><h2 className="text-2xl font-bold text-foreground">How to Calculate GCF Using Prime Factorization</h2><p className="text-muted-foreground leading-relaxed">Prime factor each number, keep only factors shared by all numbers, and multiply their lowest powers.</p><h2 className="text-2xl font-bold text-foreground">Free GCF Math Tool for Students</h2><p className="text-muted-foreground leading-relaxed">Use this GCD calculator free for fraction simplification, factoring, and number theory homework.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/gcf-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


